module mux2to1_32bit (
    input sel,
    input [31:0] in0,
    input [31:0] in1,
    output [31:0] out
);

    reg [31:0] invalid_mux_output;  // Multiplexer output register

    always @(*) begin
        case (sel)
            1'b0: invalid_mux_output = in0;
            1'b1: invalid_mux_output = in1;
            default: invalid_mux_output = 32'b0;  // Default case (should not occur)
        endcase
    end

    assign out = invalid_mux_output;

endmodule
